#[derive(Serialize, Clone, Debug)]
pub struct NetworkTimeEntry {
    pub id: i64,
    pub description: String,
    pub start: DateTime<Utc>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub stop: Option<DateTime<Utc>>,
    pub duration: i64,
    pub billable: bool,
    #[serde(alias = "wid")]
    pub workspace_id: i64,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub tags: Option<Vec<String>>,
    #[serde(alias = "pid")]
    #[serde(skip_serializing_if = "Option::is_none")]
    pub project_id: Option<i64>,
    #[serde(alias = "tid")]
    #[serde(skip_serializing_if = "Option::is_none")]
    pub task_id: Option<i64>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub created_with: Option<String>,
}

#[derive(Deserialize)]
struct RawNetworkTimeEntry {
    id: i64,
    description: String,
    start: DateTime<Utc>,
    stop: Option<DateTime<Utc>>,
    duration: i64,
    billable: bool,
    workspace_id: Option<i64>,
    wid: Option<i64>,
    tags: Option<Vec<String>>,
    project_id: Option<i64>,
    pid: Option<i64>,
    task_id: Option<i64>,
    tid: Option<i64>,
    created_with: Option<String>,
}

impl<'de> Deserialize<'de> for NetworkTimeEntry {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        let raw = RawNetworkTimeEntry::deserialize(deserializer)?;
        Ok(Self {
            id: raw.id,
            description: raw.description,
            start: raw.start,
            stop: raw.stop,
            duration: raw.duration,
            billable: raw.billable,
            workspace_id: raw
                .workspace_id
                .or(raw.wid)
                .ok_or_else(|| serde::de::Error::missing_field("workspace_id"))?,
            tags: raw.tags,
            project_id: raw.project_id.or(raw.pid),
            task_id: raw.task_id.or(raw.tid),
            created_with: raw.created_with,
        })
    }
}

