use crate::api::client::ApiClient;
use crate::models::{ResultWithDefaultError, TimeEntry};
use crate::utilities;
use std::collections::HashMap;

const BILLING_UNIT_SECONDS: i64 = 15 * 60;
const NO_PROJECT: &str = "No Project";

pub struct BillCommand;

fn rounded_duration(seconds: i64) -> i64 {
    ((seconds + BILLING_UNIT_SECONDS - 1) / BILLING_UNIT_SECONDS) * BILLING_UNIT_SECONDS
}

fn aggregate(entries: &[TimeEntry]) -> Vec<(String, i64)> {
    let mut totals = HashMap::<String, i64>::new();

    for entry in entries {
        if !entry.billable || entry.stop.is_none() || entry.duration <= 0 {
            continue;
        }

        let project = entry
            .project
            .as_ref()
            .map(|project| project.name.clone())
            .unwrap_or_else(|| NO_PROJECT.to_string());
        *totals.entry(project).or_default() += rounded_duration(entry.duration);
    }

    let mut totals: Vec<_> = totals.into_iter().collect();
    totals.sort_by(|(left_name, left_seconds), (right_name, right_seconds)| {
        right_seconds
            .cmp(left_seconds)
            .then_with(|| left_name.cmp(right_name))
    });
    totals
}

fn render(totals: &[(String, i64)]) -> String {
    if totals.is_empty() {
        return "(no data)\n".to_string();
    }

    let total: i64 = totals.iter().map(|(_, seconds)| seconds).sum();
    let mut output = totals
        .iter()
        .map(|(project, seconds)| format!("{seconds}s  {project}"))
        .collect::<Vec<_>>();
    output.push(format!("{total}s  Total"));
    format!("{}\n", output.join("\n"))
}

impl BillCommand {
    pub async fn execute(
        api_client: impl ApiClient,
        since: Option<String>,
        until: Option<String>,
    ) -> ResultWithDefaultError<()> {
        let (since, until) = utilities::normalize_time_entry_list_filters(since, until)?;
        let entries = api_client.get_time_entries_filtered(since, until).await?;
        print!("{}", render(&aggregate(&entries)));
        Ok(())
    }
}

